// ============================================
// VALIDAR TENANT Y VERIFICAR PAGO
// ============================================

const input = $input.item.json;
const tenant = input.tenant_slug || input.tenant;
const product = input.product_id;
const quantity = input.quantity || 1;

// Verificar si el tenant tiene pago activo
const hasPayment = input.payment_confirmed === true || input.api_key_valid === true;

if (!hasPayment) {
  // Generar orden de pago
  const orderId = `PAY-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

  return {
    json: {
      status: "payment_required",
      message: "Sin pago activo. Generando orden de pago...",
      order_id: orderId,
      tenant: tenant,
      product: product,
      quantity: quantity,
      payment_url: `https://flow.cl/btn.php?token=ORDER_${orderId}`,
      next_step: "redirect_to_payment"
    }
  };
}

return {
  json: {
    status: "approved",
    message: "Servicio activo — pago confirmado",
    tenant: tenant,
    product: product,
    quantity: quantity
  }
};

// ============================================
// PROCESAR CONFIRMACIÓN DE PAGO
// ============================================

const payment = $input.item.json;
const orderId = payment.order_id || payment.token;
const status = payment.status || payment.commerce_status;

if (status === 'completed' || status === 'paid') {
  return {
    json: {
      status: "payment_confirmed",
      order_id: orderId,
      message: "✅ Pago confirmado — activando servicio",
      action: "activate_tenant",
      tenant: payment.tenant_slug,
      amount: payment.amount,
      timestamp: new Date().toISOString()
    }
  };
}

return {
  json: {
    status: "payment_pending",
    order_id: orderId,
    message: "⏳ Pago pendiente",
    action: "wait_for_payment"
  }
};

// ============================================
// DTE FACTURACIÓN ELECTRÓNICA
// ============================================

const payment = $input.item.json;

if (payment.status === 'payment_confirmed') {
  const dteData = {
    tipo_dte: 39, // Boleta electrónica
    receptor_rut: payment.client_rut || '00000000-0',
    receptor_nombre: payment.client_name || 'Cliente',
    items: [{
      nombre: payment.product || 'Servicio SmarterOS',
      cantidad: 1,
      precio_unitario: payment.amount || 0
    }],
    total: payment.amount
  };

  return {
    json: {
      action: "generate_dte",
      dte: dteData,
      webhook_url: "https://libredte.cl/api/v1/boletas"
    }
  };
}

return { json: { action: "skip_dte" } };

// ============================================
// ACTUALIZAR MÉTRICAS DE FUNNEL
// ============================================

const checkout = $input.item.json;
const tenant = checkout.tenant_slug || checkout.tenant;

return {
  json: {
    action: "update_funnel_metrics",
    tenant_slug: tenant,
    date: new Date().toISOString().split('T')[0],
    checkouts_completed: 1,
    revenue_total: checkout.amount || 0,
    currency: checkout.currency || 'CLP'
  }
};
